(()=>{"use strict";chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"startRecord",title:"녹화 시작하기"})}),chrome.contextMenus.onClicked.addListener((e,t)=>{t?.id&&chrome.scripting.executeScript({files:["dist/content.js"],target:{tabId:t.id},world:"MAIN"}).catch(e=>{console.error("[Entry Recorder] 스크립트 주입 실패",e)})})})();